// Parse AI Agent output (raw JSON or inside a markdown code fence),
// merge with context from Read Incident Context and SetVars,
// and build a Jira payload including a Slack permalink to the source message.

function buildSlackPermalink(archivesBase, channelId, messageTs, options = {}) {
  const { threadTs, isThread } = options;
  if (!archivesBase || !channelId || !messageTs) return null;

  const base = String(archivesBase).replace(/\/+$/, '');
  const ts = String(messageTs).trim();
  const pTs = ts.startsWith('p') ? ts : `p${ts.replace('.', '')}`;

  let url = `${base}/${channelId}/${pTs}`;

  // Reply in thread: open the correct message inside the thread
  if (isThread && threadTs && String(threadTs).trim() !== ts) {
    url += `?thread_ts=${encodeURIComponent(String(threadTs).trim())}&cid=${encodeURIComponent(channelId)}`;
  }

  return url;
}

const raw = $input.first().json.output ?? '';
const ctx = $('Read Incident Context').first().json;
const vars = $('SetVars').first().json;

const cleaned = String(raw)
  .replace(/^\s*```(?:json)?\s*/i, '')
  .replace(/\s*```\s*$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error(`Failed to parse AI Agent output as JSON: ${err.message}. Raw output was: ${raw}`);
}

const isThread = ctx.is_thread === true || ctx.is_thread === 'true';

const slackLink = buildSlackPermalink(
  vars.SLACK_URL,
  ctx.channel_id,
  ctx.post_id,
  {
    isThread,
    threadTs: ctx.thread_root_id,
  },
);

const sourceLines = [
  '',
  '---',
  `*Source:* @${ctx.user_name || 'unknown'} in channel #${ctx.channel_name || parsed.channel_name || 'unknown'}`,
];

if (slackLink) {
  sourceLines.push(`*Slack message link:* ${slackLink}`);
}

if (ctx.summary) {
  sourceLines.push(`*Classification:* ${ctx.summary} (confidence: ${ctx.confidence ?? 'n/a'})`);
}

const description = `${parsed.description || ''}\n${sourceLines.join('\n')}`;

return [{
  json: {
    summary: parsed.summary || '(no summary)',
    description,
    label: parsed.label || 'Operations',
    user_name: ctx.user_name,
    on_call_user: ctx.on_call_user,
    channel_id: ctx.channel_id,
    post_id: ctx.post_id,
    slack_message_link: slackLink,
    agent_raw_output: raw,
  },
}];
